import SequenceScroll from './components/SequenceScroll';
import TextReveal from './components/TextReveal';
import CountUpOnView from './components/CountUpOnView';
import TestimonialsSlider from './components/TestimonialsSlider';
import Navbar from './components/Navbar';

export default function HomePage() {
  return (
    <main className="min-h-screen bg-[#0f0b08] text-white overflow-hidden">
      <Navbar />
      <SequenceScroll />

      <section className="relative -mt-[100vh] z-10 bg-[#0f0b08] pt-[120vh] pb-24">
        <div className="mx-auto flex max-w-7xl flex-col gap-20 px-6 md:px-10">
          <div className="grid gap-12 lg:grid-cols-[1.1fr_minmax(280px,0.9fr)]">
            <div className="space-y-6">
              <p className="text-sm uppercase tracking-[0.36em] text-rose-200/80">About Aromea</p>
              <h2 className="text-5xl font-semibold tracking-tight text-white md:text-6xl">
                A luxury fragrance brand narrative built around scent, motion and refined artistry.
              </h2>
              <p className="max-w-2xl text-lg leading-8 text-stone-300/90">
                Aromea is designed to feel like cinema. Every scroll reveals a new chapter of fragrance craftsmanship, essence extraction, and sensory moments designed for the modern perfume connoisseur.
              </p>
            </div>
            <div className="rounded-[2rem] border border-white/10 bg-white/5 p-8 backdrop-blur-xl">
              <TextReveal text="The brand philosophy flows through every note. Each scent is a composition of rare materials, artisanal blending, and emotional resonance. Aromea is luxury in motion." />
            </div>
          </div>

          <div className="grid gap-8 lg:grid-cols-3">
            {['Essence crafted', 'Rare ingredients', 'Signature notes'].map((title, index) => (
              <div key={title} className="group overflow-hidden rounded-[2rem] border border-white/10 bg-[#130d09]/80 p-8 transition hover:-translate-y-1 hover:border-rose-200/30 hover:bg-[#1c1410]/90">
                <div className="h-64 overflow-hidden rounded-[1.75rem] bg-stone-950/50">
                  <div className="h-full w-full bg-[radial-gradient(circle_at_top,_rgba(244,_114,_182,_0.24),_transparent_35%)]" />
                </div>
                <h3 className="mt-7 text-2xl font-semibold text-white">{title}</h3>
                <p className="mt-4 text-sm leading-7 text-stone-300/85">
                  A modern perfume story built around elegance, emotion, and the art of olfactory design.
                </p>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section className="bg-[#100b08] py-24">
        <div className="mx-auto max-w-7xl px-6 md:px-10">
          <div className="grid gap-12 xl:grid-cols-[1.2fr_0.8fr]">
            <div className="space-y-8">
              <p className="text-sm uppercase tracking-[0.36em] text-rose-200/80">Numbers that matter</p>
              <h2 className="text-4xl font-semibold tracking-tight text-white md:text-5xl">
                Real fragrances, real passion.
              </h2>
              <p className="max-w-2xl text-base leading-8 text-stone-300/85">
                Each metric is a story point — from precious essences sourced globally to fragrance enthusiasts inspired by Aromea's artistry.
              </p>
            </div>
            <div className="grid gap-6 sm:grid-cols-3">
              <CountUpOnView label="Perfumes" value={24} suffix="+" />
              <CountUpOnView label="Rarities" value={18} suffix="" />
              <CountUpOnView label="Awards" value={12} suffix="" />
            </div>
          </div>
        </div>
      </section>

      <section className="bg-[#0f0b08] py-24">
        <div className="mx-auto max-w-7xl px-6 md:px-10">
          <div className="mb-16 text-center">
            <p className="text-sm uppercase tracking-[0.36em] text-rose-200/80">Praise from the collection</p>
            <h2 className="mt-6 text-5xl font-semibold tracking-tight text-white md:text-6xl">
              Testimonials that capture elegance.
            </h2>
          </div>
          <TestimonialsSlider />
        </div>
      </section>

      <section className="relative overflow-hidden bg-[#140c08] py-28">
        <div className="pointer-events-none absolute inset-0 bg-[radial-gradient(circle_at_center,_rgba(244,114,182,0.12),_transparent_25%)]" />
        <div className="absolute inset-x-0 top-0 h-1/2 bg-gradient-to-b from-rose-600/10 to-transparent" />
        <div className="mx-auto relative max-w-6xl px-6 md:px-10 text-center">
          <p className="text-sm uppercase tracking-[0.36em] text-rose-200/80">Aromea Collective</p>
          <h2 className="mt-6 text-5xl font-semibold tracking-tight text-white md:text-6xl">
            Join us for a fragrance journey that moves with every scroll.
          </h2>
          <p className="mx-auto mt-6 max-w-2xl text-lg leading-8 text-stone-300/85">
            From exclusive releases to limited-edition blends, Aromea is where luxury perfumery intersects with a modern interactive brand experience.
          </p>
          <div className="mt-12 flex flex-col items-center justify-center gap-4 sm:flex-row">
            <button className="inline-flex items-center justify-center rounded-full bg-gradient-to-r from-rose-400 via-pink-300 to-rose-300 px-10 py-4 text-base font-semibold uppercase tracking-[0.2em] text-[#3d0a1f] shadow-[0_20px_60px_rgba(244,114,182,0.2)] transition duration-300 hover:-translate-y-1">
              Discover scents
            </button>
            <button className="inline-flex items-center justify-center rounded-full border border-white/15 bg-white/5 px-10 py-4 text-base font-semibold uppercase tracking-[0.2em] text-white transition duration-300 hover:border-rose-200/40 hover:bg-white/10">
              Schedule consultation
            </button>
          </div>
        </div>
      </section>

      <footer className="bg-[#090705] py-16 text-stone-400">
        <div className="mx-auto flex max-w-7xl flex-col gap-6 px-6 md:flex-row md:items-center md:justify-between md:px-10">
          <div>
            <p className="text-lg font-semibold text-white">Aromea</p>
            <p className="mt-3 max-w-xl text-sm leading-7 text-stone-400/90">
              An immersive coffee brand designed for a new generation of taste, ritual, and visual storytelling.
            </p>
          </div>
          <div className="flex flex-wrap gap-5 text-sm uppercase tracking-[0.3em] text-stone-500">
            <span>Contact</span>
            <span>Instagram</span>
            <span>Press</span>
          </div>
        </div>
      </footer>
    </main>
  );
}
